using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;

string a,b;
map<string,bool> bk;
queue<pair<string,pair<ll,string>>> q;

il bool chk(string s)
{
	return a==s;
}
il string A(string s)
{
	swap(s[0],s[7]);
	swap(s[1],s[6]);
	swap(s[2],s[5]);
	swap(s[3],s[4]);
	return s;
}
il string B(string s)
{
	swap(s[0],s[3]);
	swap(s[4],s[7]);
	swap(s[1],s[3]);
	swap(s[4],s[6]);
	swap(s[2],s[3]);
	swap(s[4],s[5]);
	return s;
}
il string C(string s)
{
	swap(s[1],s[6]);
	swap(s[5],s[6]);
	swap(s[2],s[5]);
	return s;
}

signed main(void)
{
	FOR(i,1,8)
	{
		ll x=read();
		a+=to_string(x);
	}
	b="12345678";
	if(chk(b))
	{
		write(0);
		return 0;
	}
	q.push(mk(b,mk(0,"")));
	bk[b]=1;
	wh(!q.empty())
	{
		string u=q.front().fst;
		ll stp=q.front().snd.fst;
		string ans=q.front().snd.snd;
		q.pop();
		string v=A(u);
		if(!bk[v])
		{
			q.push(mk(v,mk(stp+1,ans+'A')));
			bk[v]=1;
		}
		if(chk(v))
		{
			writeln(stp+1);
			cout<<ans+'A';
			return 0;
		}
		v=B(u);
		if(!bk[v])
		{
			q.push(mk(v,mk(stp+1,ans+'B')));
			bk[v]=1;
		}
		if(chk(v))
		{
			writeln(stp+1);
			cout<<ans+'B';
			return 0;
		}
		v=C(u);
		if(!bk[v])
		{
			q.push(mk(v,mk(stp+1,ans+'C')));
			bk[v]=1;
		}
		if(chk(v))
		{
			writeln(stp+1);
			cout<<ans+'C';
			return 0;
		}
	}
	return false;
}
